INSERT INTO t_p57647769_pwa_login_app.admin_tasks (assignee, status, comment, note) VALUES
('Юра', 'open',
 'Реализовать логирование подписания по СМС (юридическая сила ПЭП)',
 'КЛЮЧЕВОЙ технический момент для юридической силы простой электронной подписи (63-ФЗ). При входе/подтверждении по СМС сохранять в базу журнал подписания: номер телефона, дата и время, код (или его хэш), версия/редакция документа, с которым согласился пользователь, данные сессии (IP, устройство). Без этого журнала ПЭП юридически «повисает» — нечем доказать факт и содержание согласия. Связано с Документом 3 (Согласие на ПДн + ПЭП). Реализуем после утверждения текстов юристом.');